1	-------------------------------------------------------------------------------
2	-- Company    : SLAC National Accelerator Laboratory
3	-------------------------------------------------------------------------------
4	-- Description: General AXI RAM Module
5	-------------------------------------------------------------------------------
6	-- This file is part of 'SLAC Firmware Standard Library'.
7	-- It is subject to the license terms in the LICENSE.txt file found in the
8	-- top-level directory of this distribution and at:
9	--    https://confluence.slac.stanford.edu/display/ppareg/LICENSE.html.
10	-- No part of 'SLAC Firmware Standard Library', including this file,
11	-- may be copied, modified, propagated, or distributed except according to
12	-- the terms contained in the LICENSE.txt file.
13	-------------------------------------------------------------------------------
14	
15	library ieee;
16	use ieee.std_logic_1164.all;
17	use ieee.std_logic_arith.all;
18	use ieee.std_logic_unsigned.all;
19	
20	library surf;
21	use surf.StdRtlPkg.all;
22	use surf.AxiPkg.all;
23	
24	entity AxiRam is
25	   generic (
26	      TPD_G          : time                 := 1 ns;
27	      SYNTH_MODE_G   : string               := "inferred";
28	      MEMORY_TYPE_G  : string               := "block";
29	      READ_LATENCY_G : natural range 0 to 2 := 2;
30	      AXI_CONFIG_G   : AxiConfigType);
31	   port (
32	      -- Clock and Reset
33	      axiClk          : in  sl;
34	      axiRst          : in  sl;
35	      -- Slave Write Interface
36	      sAxiWriteMaster : in  AxiWriteMasterType;
37	      sAxiWriteSlave  : out AxiWriteSlaveType;
38	      -- Slave Read Interface
39	      sAxiReadMaster  : in  AxiReadMasterType;
40	      sAxiReadSlave   : out AxiReadSlaveType);
41	end AxiRam;
42	
43	architecture structure of AxiRam is
44	
45	   constant DATA_BYTES_C : positive := AXI_CONFIG_G.DATA_BYTES_C;
46	   constant DATA_WIDTH_C : positive := 8*DATA_BYTES_C;
47	   constant OFFSET_C     : positive := ite(DATA_BYTES_C = 1, 0, log2(DATA_BYTES_C));
48	   constant ADDR_WIDTH_C : positive := AXI_CONFIG_G.ADDR_WIDTH_C-OFFSET_C;
49	
50	   type WrStateType is (
51	      WR_ADDR_S,
52	      WR_DATA_S,
53	      WR_BLOWOFF_S);
54	
55	   type RdStateType is (
56	      RD_ADDR_S,
57	      RD_PIPELINE_S,
58	      RD_DATA_S);
59	
60	   type RegType is record
61	      -- Write Signals
62	      wrData         : slv(DATA_WIDTH_C-1 downto 0);
63	      wrAddr         : slv(ADDR_WIDTH_C-1 downto 0);
64	      wstrb          : slv(DATA_BYTES_C-1 downto 0);
65	      wid            : slv(31 downto 0);
66	      awlen          : slv(7 downto 0);
67	      sAxiWriteSlave : AxiWriteSlaveType;
68	      wrState        : WrStateType;
69	      -- Read Signals
70	      rdAddr         : slv(ADDR_WIDTH_C-1 downto 0);
71	      rid            : slv(31 downto 0);
72	      arlen          : slv(7 downto 0);
73	      sAxiReadSlave  : AxiReadSlaveType;
74	      rdEn           : slv(1 downto 0);
75	      rdLat          : slv(1 downto 0);
76	      rdState        : RdStateType;
77	   end record;
78	
79	   constant REG_INIT_C : RegType := (
80	      -- Write Signals
81	      wrData         => (others => '0'),
82	      wrAddr         => (others => '0'),
83	      wstrb          => (others => '0'),
84	      wid            => (others => '0'),
85	      awlen          => (others => '0'),
86	      sAxiWriteSlave => AXI_WRITE_SLAVE_INIT_C,
87	      wrState        => WR_ADDR_S,
88	      -- Read Signals
89	      rdAddr         => (others => '0'),
90	      rid            => (others => '0'),
91	      arlen          => (others => '0'),
92	      sAxiReadSlave  => AXI_READ_SLAVE_INIT_C,
93	      rdEn           => (others => '0'),
94	      rdLat          => (others => '0'),
95	      rdState        => RD_ADDR_S);
96	
97	   signal r   : RegType := REG_INIT_C;
98	   signal rin : RegType;
99	
100	
101	   signal wrEn   : sl;
102	   signal wrData : slv(DATA_WIDTH_C-1 downto 0);
103	   signal wrAddr : slv(ADDR_WIDTH_C-1 downto 0);
104	   signal wstrb  : slv(DATA_BYTES_C-1 downto 0);
105	
106	   signal rdEn   : slv(1 downto 0);
107	   signal rdData : slv(DATA_WIDTH_C-1 downto 0);
108	   signal rdAddr : slv(ADDR_WIDTH_C-1 downto 0);
109	
110	begin
111	
112	   assert (SYNTH_MODE_G /= "inferred") or
113	      ((SYNTH_MODE_G = "inferred") and (READ_LATENCY_G > 0))
114	      report "AxiRam: Inferred SimpleDualPortRam does not support zero latency reads" severity failure;
115	
116	   GEN_XPM : if (SYNTH_MODE_G = "xpm") generate
117	      U_RAM : entity surf.SimpleDualPortRamXpm
118	         generic map (
119	            TPD_G          => TPD_G,
120	            COMMON_CLK_G   => true,
121	            MEMORY_TYPE_G  => MEMORY_TYPE_G,
122	            READ_LATENCY_G => READ_LATENCY_G,
123	            DATA_WIDTH_G   => DATA_WIDTH_C,
124	            BYTE_WR_EN_G   => true,
125	            BYTE_WIDTH_G   => 8,
126	            ADDR_WIDTH_G   => ADDR_WIDTH_C)
127	         port map (
128	            -- Port A
129	            ena    => wrEn,
130	            clka   => axiClk,
131	            addra  => wrAddr,
132	            dina   => wrData,
133	            wea    => wstrb,
134	            -- Read Interface
135	            enb    => rdEn(0),
136	            clkb   => axiClk,
137	            addrb  => rdAddr,
138	            doutb  => rdData,
139	            regceb => rdEn(1));
140	   end generate;
141	
142	   GEN_ALTERA : if (SYNTH_MODE_G = "altera_mf") generate
143	      U_RAM : entity surf.SimpleDualPortRamAlteraMf
144	         generic map (
145	            TPD_G          => TPD_G,
146	            COMMON_CLK_G   => true,
147	            MEMORY_TYPE_G  => MEMORY_TYPE_G,
148	            READ_LATENCY_G => READ_LATENCY_G,
149	            DATA_WIDTH_G   => DATA_WIDTH_C,
150	            BYTE_WR_EN_G   => true,
151	            BYTE_WIDTH_G   => 8,
152	            ADDR_WIDTH_G   => ADDR_WIDTH_C)
153	         port map (
154	            -- Port A
155	            ena    => wrEn,
156	            clka   => axiClk,
157	            addra  => wrAddr,
158	            dina   => wrData,
159	            wea    => wstrb,
160	            -- Read Interface
161	            enb    => rdEn(0),
162	            clkb   => axiClk,
163	            addrb  => rdAddr,
164	            doutb  => rdData,
165	            regceb => rdEn(1));
166	   end generate;
167	
168	   GEN_INFERRED : if (SYNTH_MODE_G = "inferred") generate
169	      U_RAM : entity surf.SimpleDualPortRam
170	         generic map (
171	            TPD_G         => TPD_G,
172	            MEMORY_TYPE_G => MEMORY_TYPE_G,
173	            DOB_REG_G     => ite(READ_LATENCY_G = 2, true, false),
174	            BYTE_WR_EN_G  => true,
175	            DATA_WIDTH_G  => DATA_WIDTH_C,
176	            BYTE_WIDTH_G  => 8,
177	            ADDR_WIDTH_G  => ADDR_WIDTH_C)
178	         port map (
179	            -- Port A
180	            ena     => wrEn,
181	            clka    => axiClk,
182	            addra   => wrAddr,
183	            dina    => wrData,
184	            weaByte => wstrb,
185	            -- Read Interface
186	            enb     => rdEn(0),
187	            clkb    => axiClk,
188	            addrb   => rdAddr,
189	            doutb   => rdData,
190	            regceb  => rdEn(1));
191	   end generate;
192	
193	   comb : process (axiRst, r, rdData, sAxiReadMaster, sAxiWriteMaster) is
194	      variable v : RegType;
195	   begin
196	      -- Latch the current value
197	      v := r;
198	
199	      ----------------------------------------------------------------------
200	      --                      AXI Write Logic                             --
201	      ----------------------------------------------------------------------
202	
203	      -- Reset the strobes
204	      v.wstrb                  := (others => '0');
205	      v.sAxiWriteSlave.awready := '0';
206	      v.sAxiWriteSlave.wready  := '0';
207	      if (sAxiWriteMaster.bready = '1') then
208	         v.sAxiWriteSlave.bvalid := '0';
209	      end if;
210	
211	      -- Write State Machine
212	      case (r.wrState) is
213	         ----------------------------------------------------------------------
214	         when WR_ADDR_S =>
215	            -- Wait for the Address transaction
216	            if (sAxiWriteMaster.awvalid = '1') then
217	               -- Accept the transaction
218	               v.sAxiWriteSlave.awready := '1';
219	               -- Slave the channel ID
220	               v.wid                    := sAxiWriteMaster.awid;
221	               -- Save the address
222	               v.wrAddr                 := sAxiWriteMaster.awaddr((ADDR_WIDTH_C-1)+OFFSET_C downto OFFSET_C);
223	               -- Pre-decrement (registered output)
224	               v.wrAddr                 := v.wrAddr - 1;
225	               -- latch the length
226	               v.awlen                  := sAxiWriteMaster.awlen;
227	               -- Next State
228	               v.wrState                := WR_DATA_S;
229	            end if;
230	         ----------------------------------------------------------------------
231	         when WR_DATA_S =>
232	            -- Check if ready to move data
233	            if (sAxiWriteMaster.wvalid = '1') and (r.sAxiWriteSlave.bvalid = '0') then
234	               -- Accept the data
235	               v.sAxiWriteSlave.wready := '1';
236	               -- Increment the address
237	               v.wrAddr                := r.wrAddr + 1;
238	               -- Write the data to RAM
239	               v.wstrb                 := sAxiWriteMaster.wstrb(DATA_BYTES_C-1 downto 0);
240	               v.wrData                := sAxiWriteMaster.wdata(DATA_WIDTH_C-1 downto 0);
241	               -- Decrement the counter
242	               v.awlen                 := r.awlen - 1;
243	               -- Check for last transfer
244	               if (sAxiWriteMaster.wlast = '1') or (r.awlen = 0) then
245	                  v.sAxiWriteSlave.bvalid := '1';
246	                  v.sAxiWriteSlave.bid    := r.wid;
247	                  -- Check alignment
248	                  if (sAxiWriteMaster.wlast = '1') and (r.awlen = 0) then
249	                     -- Access OK
250	                     v.sAxiWriteSlave.bresp := "00";
251	                     -- Next State
252	                     v.wrState              := WR_ADDR_S;
253	                  else
254	                     -- Slave Error
255	                     v.sAxiWriteSlave.bresp := "10";
256	                     -- Check for last transfer
257	                     if (sAxiWriteMaster.wlast = '1') then
258	                        -- Next State
259	                        v.wrState := WR_ADDR_S;
260	                     else
261	                        -- Next State
262	                        v.wrState := WR_BLOWOFF_S;
263	                     end if;
264	                  end if;
265	               end if;
266	            end if;
267	         ----------------------------------------------------------------------
268	         when WR_BLOWOFF_S =>
269	            -- Blow off the data
270	            v.sAxiWriteSlave.wready := '1';
271	            -- Check for last transfer
272	            if (sAxiWriteMaster.wvalid = '1') and (sAxiWriteMaster.wlast = '1') then
273	               -- Next State
274	               v.wrState := WR_ADDR_S;
275	            end if;
276	      ----------------------------------------------------------------------
277	      end case;
278	
279	      -- Outputs
280	      wrEn   <= uOr(r.wstrb);
281	      wstrb  <= r.wstrb;
282	      wrAddr <= r.wrAddr;
283	      wrData <= r.wrData;
284	
285	      --------------------------
286	      -- sAxiWriteSlave's Outputs
287	      --------------------------
288	      -- Write address channel
289	      sAxiWriteSlave.awready <= v.sAxiWriteSlave.awready;
290	      -- Write data channel
291	      sAxiWriteSlave.wready  <= v.sAxiWriteSlave.wready;
292	      -- Write ack channel
293	      sAxiWriteSlave.bresp   <= r.sAxiWriteSlave.bresp;
294	      sAxiWriteSlave.bvalid  <= r.sAxiWriteSlave.bvalid;
295	      sAxiWriteSlave.bid     <= r.sAxiWriteSlave.bid;
296	
297	      ----------------------------------------------------------------------
298	      --                      AXI Read Logic                              --
299	      ----------------------------------------------------------------------
300	
301	      -- Reset the strobes
302	      v.sAxiReadSlave.arready := '0';
303	      if (sAxiReadMaster.rready = '1') then
304	         v.sAxiReadSlave.rvalid := '0';
305	         v.sAxiReadSlave.rlast  := '0';
306	      end if;
307	
308	      -- Write State Machine
309	      case (r.rdState) is
310	         ----------------------------------------------------------------------
311	         when RD_ADDR_S =>
312	            -- Wait for the Address transaction
313	            if (sAxiReadMaster.arvalid = '1') then
314	               -- Accept the transaction
315	               v.sAxiReadSlave.arready := '1';
316	               -- Slave the channel ID
317	               v.rid                   := sAxiReadMaster.arid;
318	               -- Save the address
319	               v.rdAddr                := sAxiReadMaster.araddr((ADDR_WIDTH_C-1)+OFFSET_C downto OFFSET_C);
320	               -- Enable RAM reads
321	               v.rdEn                  := "11";
322	               -- latch the length
323	               v.arlen                 := sAxiReadMaster.arlen;
324	               -- Check the read latency
325	               if (READ_LATENCY_G = 0) then
326	                  -- Next State
327	                  v.rdState := RD_DATA_S;
328	               else
329	                  -- Next State
330	                  v.rdState := RD_PIPELINE_S;
331	               end if;
332	            end if;
333	         ----------------------------------------------------------------------
334	         when RD_PIPELINE_S =>
335	            -- Enable RAM reads
336	            v.rdEn   := "11";
337	            -- Increment the address
338	            v.rdAddr := r.rdAddr + 1;
339	            -- Check if RAM pipeline is filled
340	            if (r.rdLat = READ_LATENCY_G-1) then
341	               -- Reset the counter
342	               v.rdLat   := (others => '0');
343	               -- Next State
344	               v.rdState := RD_DATA_S;
345	            else
346	               -- Increment the counter
347	               v.rdLat := r.rdLat + 1;
348	            end if;
349	         ----------------------------------------------------------------------
350	         when RD_DATA_S =>
351	            --  Hold the pipeline
352	            v.rdEn := "00";
353	            -- Check if ready to move data
354	            if (v.sAxiReadSlave.rvalid = '0') then
355	               -- Accept the data from the rate
356	               v.rdEn                                         := "11";
357	               -- Forward the data
358	               v.sAxiReadSlave.rvalid                         := '1';
359	               v.sAxiReadSlave.rdata(DATA_WIDTH_C-1 downto 0) := rdData;
360	               v.sAxiReadSlave.rid                            := r.rid;
361	               -- Increment the address
362	               v.rdAddr                                       := r.rdAddr + 1;
363	               -- Decrement the counter
364	               v.arlen                                        := r.arlen - 1;
365	               -- Check for last transfer
366	               if (r.arlen = 0) then
367	                  -- Set the last transfer flag
368	                  v.sAxiReadSlave.rlast := '1';
369	                  -- Next State
370	                  v.rdState             := RD_ADDR_S;
371	               end if;
372	            end if;
373	      ----------------------------------------------------------------------
374	      end case;
375	
376	      -- Outputs
377	      rdAddr <= r.rdAddr;
378	      if (READ_LATENCY_G = 0) then
379	         rdEn <= "11";
380	      else
381	         rdEn <= v.rdEn;
382	      end if;
383	
384	      --------------------------
385	      -- sAxiReadSlave's Outputs
386	      --------------------------
387	      -- Read Address channel
388	      sAxiReadSlave.arready <= v.sAxiReadSlave.arready;
389	      -- Read data channel
390	      sAxiReadSlave.rdata   <= r.sAxiReadSlave.rdata;
391	      sAxiReadSlave.rlast   <= r.sAxiReadSlave.rlast;
392	      sAxiReadSlave.rvalid  <= r.sAxiReadSlave.rvalid;
393	      sAxiReadSlave.rid     <= r.sAxiReadSlave.rid;
394	      sAxiReadSlave.rresp   <= r.sAxiReadSlave.rresp;
395	
396	      -- Reset
397	      if (axiRst = '1') then
398	         v := REG_INIT_C;
399	      end if;
400	
401	      -- Register the variable for next clock cycle
402	      rin <= v;
403	
404	   end process comb;
405	
406	   seq : process (axiClk) is
407	   begin
408	      if (rising_edge(axiClk)) then
409	         r <= rin after TPD_G;
410	      end if;
411	   end process seq;
412	
413	end structure;
414

